file_path = "/Users/takumi.ikeda/運動タイプ診断/ドキュメント/05_1対15比較図/GFVC_温もり提供者_vs_その他15タイプ.md"

with open(file_path, "r", encoding="utf-8") as f:
    content = f.read()

for pair_key, texts in pairs_data.items():
    # Regex to find the section for the specific pair
    # Assuming sections start with `## vs [XXXX]`
    pattern = re.compile(r"(## vs \[" + pair_key + r"\].*?)(?=## vs \[|\Z)", re.DOTALL)
    
    def replacer(match):
        section_content = match.group(1)
        
        # Replace 相性解説
        section_content = re.sub(
            r"(### 相性解説\n\n).*?(?=\n\n### 一緒に楽しむコツ)",
            r"\g<1>" + texts["desc"],
            section_content,
            flags=re.DOTALL
        )
        
        # Replace 一緒に楽しむコツ
        section_content = re.sub(
            r"(### 一緒に楽しむコツ\n\n).*?(?=\n\n### 摩擦ポイント)",
            r"\g<1>" + texts["tips"],
            section_content,
            flags=re.DOTALL
        )
        
        # Replace 摩擦ポイント
        section_content = re.sub(
            r"(### 摩擦ポイント\n\n).*?(?=\n\n### 目的の持ち方)",
            r"\g<1>" + texts["friction"],
            section_content,
            flags=re.DOTALL
        )
        
        return section_content

    content = pattern.sub(replacer, content)

with open(file_path, "w", encoding="utf-8") as f:
    f.write(content)

print("Done")
